let initialLoadDone = false; // ★ Devient true seulement après un chargement réussi depuis Sheets

async function saveMissionsToSheets() {
  try {
    // ★ GARDE-FOU CRITIQUE : ne jamais sauvegarder tant que le premier chargement
    // n'a pas réussi, et ne jamais écraser le serveur avec un tableau vide alors
    // que des missions existaient avant — c'était la cause de la disparition des
    // missions (un appareil avec des données vides/partielles en mémoire écrasait
    // le Google Sheet entier à chaque sauvegarde).
    if(!initialLoadDone){
      console.log('[Sheets] ⛔ Sauvegarde annulée : chargement initial pas encore terminé');
      return false;
    }
    if(missions.length === 0 && lastDataHash && lastDataHash !== '[]'){
      console.log('[Sheets] ⛔ Sauvegarde annulée : tableau missions vide alors que des données existaient (protection anti-écrasement)');
      return false;
    }

    // ★ text/plain évite le preflight CORS tout en envoyant le JSON correctement
    // (no-cors empêche le body d'être lu par Apps Script)
    const payload = JSON.stringify({action: 'save_missions', missions, clients, employees, chatMessages});
    await fetch(SHEETS_URL, {
      method: 'POST',
      headers: {'Content-Type': 'text/plain'},
      body: payload
    });
    lastDataHash = JSON.stringify(missions);
    console.log('[Sheets] Missions + clients + employees sauvegardés ✅ (' + missions.length + ' missions)');
    return true;
  } catch(e) {
    console.log('[Sheets] Erreur sauvegarde:', e.message);
    return false;
  }
}

async function loadMissionsFromSheets() {
  try {
    showSyncIndicator(true);
    const res = await fetch(SHEETS_URL + '?t=' + Date.now());
    const text = await res.text();
    console.log('[Sheets] Réponse (150c):', text.slice(0, 150));
    const data = JSON.parse(text);

    // Format tableau = ancien Apps Script ou nouveau sans clients/employees
    if(Array.isArray(data)){
      missions = data;
      console.log('[Sheets] Format tableau — missions:', missions.length);
    }
    // Format objet = nouveau Apps Script
    else if(data && typeof data === 'object' && !data.error){
      if(Array.isArray(data.missions)){
        missions = data.missions;
        console.log('[Sheets] Format objet — missions:', missions.length);
      }
      if(Array.isArray(data.clients) && data.clients.length > 0){
        clients = data.clients;
        nextClientId = Math.max(...clients.map(c=>c.id||0), 99) + 1;
        syncClientsToUsers();
        try { localStorage.setItem('desaem_clients', JSON.stringify(clients)); } catch(e){}
        console.log('[Sheets] Clients:', clients.length);
      }
      if(Array.isArray(data.employees) && data.employees.length > 0){
        // Fusionner sans écraser les IDs statiques
        data.employees.forEach(function(e){
          const eLogin = (e.login||'').toLowerCase();
          const existing = employees.find(emp=>(emp.login||'').toLowerCase()===eLogin);
          if(existing){
            existing.pass = e.pass || existing.pass;
            existing.actif = e.actif !== false;
            existing.nom = e.nom || existing.nom;
          } else if(e.login){
            employees.push({id:e.id, nom:e.nom, role:e.role||'Monteur', login:e.login, pass:e.pass, actif:e.actif!==false});
          }
        });
        console.log('[Sheets] Employees:', employees.map(e=>e.nom+'('+e.id+')').join(', '));
      }
      if(Array.isArray(data.chatMessages)){
        chatMessages = data.chatMessages;
        nextChatMsgId = Math.max(...chatMessages.map(c=>c.id||0), 0) + 1;
        console.log('[Sheets] Messages tchat:', chatMessages.length);
      }
    } else {
      console.log('[Sheets] Réponse inattendue:', typeof data, data && data.error);
    }

    if(missions.length > 0){
      nextMissionId = Math.max(...missions.map(m=>m.id||0), 0) + 1;
      // ★ Diagnostic : vérifier si des bons Leroy Merlin sont bien présents après chargement
      const missionsAvecBon = missions.filter(m=>m.lmBon);
      console.log('[LM] Missions avec bon Leroy Merlin reçues du serveur:', missionsAvecBon.length, missionsAvecBon.map(m=>m.client));
    }
    // Fallback localStorage clients si Sheets n'en a pas
    if(clients.length === 0){
      try {
        const local = localStorage.getItem('desaem_clients');
        if(local){ const p=JSON.parse(local); if(Array.isArray(p)&&p.length>0){ clients=p; syncClientsToUsers(); } }
      } catch(le){}
    }
    await loadEmployees();
    // ★ Chargement initial terminé avec succès : les sauvegardes sont maintenant autorisées
    initialLoadDone = true;
    lastDataHash = JSON.stringify(missions);
  } catch(e) {
    console.log('[Sheets] Erreur:', e.message);
    try {
      const local = localStorage.getItem('desaem_clients');
      if(local){ const p=JSON.parse(local); if(Array.isArray(p)&&p.length>0){clients=p;syncClientsToUsers();} }
    } catch(le){}
  } finally {
    showSyncIndicator(false);
    renderAll();
  }
}

function showSyncIndicator(loading) {
  let el = document.getElementById('sync-indicator');
  if(!el) {
    el = document.createElement('div');
    el.id = 'sync-indicator';
    el.style.cssText = 'position:fixed;top:60px;right:10px;background:var(--copper);color:white;padding:.3rem .8rem;border-radius:20px;font-size:.75rem;z-index:999;transition:opacity .3s';
    document.body.appendChild(el);
  }
  el.textContent = loading ? '⏳ Chargement...' : '✅ Synchronisé';
  el.style.opacity = '1';
  if(!loading) setTimeout(() => el.style.opacity = '0', 2000);
}

// ══ LOGIN ═════════════════════════════════════════════════════════════════════
async function doLogin(){
  const login = document.getElementById('login-user').value.trim();
  const pass = document.getElementById('login-pass').value.trim();
  const errEl = document.getElementById('login-err');
  errEl.textContent = '';

  if(!login || !pass){
    errEl.textContent = 'Veuillez remplir tous les champs';
    return;
  }

  console.log('[Login] Tentative pour:', login);

  // Cherche dans USERS (statique + admins + précédemment chargés)
  let user = USERS.find(u=>u.login.toLowerCase()===login.toLowerCase() && u.pass===pass);

  // Cherche dans employees (monteurs et admins dynamiques)
  if(!user){
    const emp = employees.find(e=>e.login && e.login.toLowerCase()===login.toLowerCase() && e.pass===pass && e.actif!==false);
    if(emp){
      user = { id:emp.id, login:emp.login, pass:emp.pass, nom:emp.nom||emp.login, role:emp.role||'Monteur', isAdmin:emp.isAdmin===true, actif:true };
      if(!USERS.find(u=>u.login.toLowerCase()===emp.login.toLowerCase())) USERS.push(user);
    }
  }

  // ★ CORRECTION BUG 2 : cherche dans clients (comptes clients)
  if(!user){
    const cli = clients.find(c=>c.login && c.login.toLowerCase()===login.toLowerCase() && c.pass===pass);
    if(cli){
      if(cli.actif === false){
        errEl.textContent = 'Ce compte est désactivé. Contactez DESAEM.';
        return;
      }
      user = { id:cli.id, login:cli.login, pass:cli.pass, nom:cli.nom, role:'client', isAdmin:false, actif:true };
      if(!USERS.find(u=>u.login.toLowerCase()===cli.login.toLowerCase())) USERS.push(user);
      console.log('[Login] Connexion client:', cli.nom);
    }
  }

  if(!user){
    errEl.textContent = 'Identifiant ou mot de passe incorrect';
    console.warn('[Login] Échec — login:', login, '| USERS:', USERS.length, '| employees:', employees.length, '| clients:', clients.length);
    return;
  }
  if(user.actif === false){
    errEl.textContent = 'Ce compte est désactivé';
    return;
  }

  console.log('[Login] ✅ Connecté:', user.nom, '| rôle:', user.role, '| id:', user.id, '(type:', typeof user.id, ')');
  currentUser = user;
  document.getElementById('login-screen').style.display='none';
  document.getElementById('app').style.display='flex';
  document.getElementById('topbar-username').textContent = user.nom + (user.isAdmin?' (Admin)':'');
  localStorage.setItem('desaem_user', JSON.stringify({id:parseInt(user.id)||user.id, login:user.login, nom:user.nom, isAdmin:user.isAdmin, role:user.role}));
  buildNav();
  // Afficher un indicateur pendant le chargement — important sur smartphone
  showToast('⏳ Chargement des missions...');
  // ★ await : missions chargées AVANT renderAll()
  await loadMissionsFromSheets();
  startAutoRefresh();
  // ★ Demander la permission de notifications après login (avec délai pour ne pas bloquer le chargement)
  setTimeout(() => requestNotificationPermission(), 3000);
  // ★ Afficher bouton calibration si admin
  if(currentUser && currentUser.isAdmin){
    const btn = document.getElementById('admin-calibration-btn');
    if(btn) btn.style.display = 'block';
  }
}

function doLogout(){
  currentUser=null;
  localStorage.removeItem('desaem_user');
  document.getElementById('login-screen').style.display='flex';
  document.getElementById('app').style.display='none';
  document.getElementById('login-user').value='';
  document.getElementById('login-pass').value='';
  document.getElementById('login-err').textContent='';
}

document.getElementById('login-pass').addEventListener('keydown',e=>{if(e.key==='Enter')doLogin()});

// ★ INIT APP — chargement complet AVANT toute tentative de login
// Garantit que clients/employees sont disponibles sur tous les appareils
(async function initApp(){
  console.log('[Init] Démarrage DESAEM...');

  // 1. localStorage en premier (instantané, fonctionne hors ligne)
  try {
    const localClients = localStorage.getItem('desaem_clients');
    if(localClients){
      const parsed = JSON.parse(localClients);
      if(Array.isArray(parsed) && parsed.length > 0){
        clients = parsed;
        nextClientId = Math.max(...clients.map(c=>c.id||0), 99) + 1;
        syncClientsToUsers();
        console.log('[Init] Clients localStorage:', clients.length, '→', clients.map(c=>c.nom).join(', '));
      }
    }
  } catch(e){ console.log('[Init] Erreur localStorage:', e.message); }

  // 2. Sheets — source de vérité commune à TOUS les appareils
  try {
    console.log('[Init] Chargement Sheets...');
    const res = await fetch(SHEETS_URL + '?t=' + Date.now());
    const text = await res.text();
    console.log('[Init] Réponse Sheets (150c):', text.slice(0, 150));
    const data = JSON.parse(text);

    if(data && !Array.isArray(data)){
      // Nouveau format : {missions, clients, employees}
      if(Array.isArray(data.missions) && data.missions.length > 0){
        missions = data.missions;
        nextMissionId = Math.max(...missions.map(m=>m.id||0), 0) + 1;
        console.log('[Init] Missions:', missions.length);
      }
      if(Array.isArray(data.clients) && data.clients.length > 0){
        clients = data.clients;
        nextClientId = Math.max(...clients.map(c=>c.id||0), 99) + 1;
        syncClientsToUsers();
        try { localStorage.setItem('desaem_clients', JSON.stringify(clients)); } catch(e){}
        console.log('[Init] ✅ Clients Sheets:', clients.length, '→', clients.map(c=>c.nom).join(', '));
      } else {
        console.log('[Init] ⚠️ Aucun client dans Sheets (data.clients:', JSON.stringify(data.clients), ')');
      }
      if(Array.isArray(data.employees) && data.employees.length > 0){
        // ★ Fusionner par login — ne jamais écraser les IDs statiques
        data.employees.forEach(function(e){
          const eLogin = (e.login||'').toLowerCase();
          const existing = employees.find(emp=>(emp.login||'').toLowerCase()===eLogin);
          if(existing){
            existing.pass = e.pass || existing.pass;
            existing.actif = e.actif !== false;
            existing.nom = e.nom || existing.nom;
            // Sync USERS avec le bon ID (statique)
            const u = USERS.find(u=>(u.login||'').toLowerCase()===eLogin);
            if(u){ u.pass=existing.pass; u.actif=existing.actif; u.id=existing.id; }
          } else if(e.login){
            employees.push({id:e.id,nom:e.nom,role:e.role||'Monteur',login:e.login,pass:e.pass,actif:e.actif!==false});
            USERS.push({id:e.id,login:e.login,pass:e.pass,nom:e.nom||e.login,role:e.role||'Monteur',isAdmin:e.isAdmin===true,actif:e.actif!==false});
          }
        });
        nextEmpId = Math.max(...employees.map(e=>e.id||0), 9) + 1;
        console.log('[Init] Employees:', employees.map(e=>e.nom+'('+e.id+')').join(', '));
      }
    } else if(Array.isArray(data)){
      // Ancien format : tableau de missions seules
      missions = data;
      nextMissionId = Math.max(...missions.map(m=>m.id||0), 0) + 1;
      console.log('[Init] ⚠️ Ancien format Sheets (missions seules):', missions.length);
    }
  } catch(ex){
    console.log('[Init] ⚠️ Sheets indisponible:', ex.message, '— utilisation localStorage');
  }

  console.log('[Init] État final — clients:', clients.length, '| employees:', employees.length, '| USERS:', USERS.length);

  // 3. Auto-login depuis session sauvegardée
  const saved = localStorage.getItem('desaem_user');
  if(!saved){ console.log('[Init] Pas de session sauvegardée'); return; }

  try {
    const u = JSON.parse(saved);
    console.log('[Init] Tentative auto-login:', u.login);

    // Cherche dans USERS (contient admins statiques + employees + clients syncClientsToUsers)
    let found = USERS.find(x=>x.login&&x.login.toLowerCase()===u.login.toLowerCase()&&x.actif!==false);

    // Fallback direct dans clients (au cas où syncClientsToUsers n'aurait pas tout pris)
    if(!found){
      const cli = clients.find(c=>c.login&&c.login.toLowerCase()===u.login.toLowerCase()&&c.actif!==false);
      if(cli) found = {id:cli.id,login:cli.login,pass:cli.pass,nom:cli.nom,role:'client',isAdmin:false,actif:true};
    }

    if(found){
      currentUser = found;
      document.getElementById('login-screen').style.display='none';
      document.getElementById('app').style.display='flex';
      document.getElementById('topbar-username').textContent = found.nom + (found.isAdmin?' (Admin)':'');
      buildNav();
      showToast('⏳ Chargement des missions...');
      await loadMissionsFromSheets();
      startAutoRefresh();
      console.log('[Init] ✅ Auto-login:', found.nom, '| rôle:', found.role);
    } else {
      localStorage.removeItem('desaem_user');
      console.log('[Init] Session invalide — compte introuvable pour:', u.login);
    }
  } catch(e){
    localStorage.removeItem('desaem_user');
    console.log('[Init] Erreur auto-login:', e.message);
  }
})();

// ══ MINI CALENDRIER LATÉRAL ═══════════════════════════════════════════════════
let miniCalMonth = new Date().getMonth();
let miniCalYear  = new Date().getFullYear();

function renderMiniCal(){
  const sidebar = document.getElementById('mini-cal-sidebar');
  if(!sidebar) return;
  // Afficher seulement pour les admins
  if(!currentUser || !currentUser.isAdmin){ sidebar.style.display='none'; return; }
  sidebar.style.display='flex';

  const container = document.getElementById('mini-cal-container');
  const today = new Date();
  const todayStr = today.toISOString().slice(0,10);

  // Dates de la semaine courante affichée
  const curWeekDates = new Set();
  if(calView === 'week' || calView === 'day'){
    const ref = new Date(calDate);
    const day = ref.getDay();
    const monday = new Date(ref);
    monday.setDate(ref.getDate() - (day===0?6:day-1));
    for(let i=0;i<7;i++){
      const d = new Date(monday); d.setDate(monday.getDate()+i);
      curWeekDates.add(d.toISOString().slice(0,10));
    }
  }

  // Missions du mois pour les points
  const missionDates = new Set(missions.map(m=>m.date));

  const monthNames = ['Janvier','Février','Mars','Avril','Mai','Juin','Juillet','Août','Septembre','Octobre','Novembre','Décembre'];
  const firstDay = new Date(miniCalYear, miniCalMonth, 1);
  const lastDay  = new Date(miniCalYear, miniCalMonth+1, 0);
  const startDow = (firstDay.getDay()+6)%7; // Lundi=0

  let html = ` <div class="mini-cal-header"> <button class="mini-cal-nav" onclick="miniCalNav(-1)">‹</button> <span class="mini-cal-title">${monthNames[miniCalMonth]} ${miniCalYear}</span> <button class="mini-cal-nav" onclick="miniCalNav(1)">›</button> </div> <div class="mini-cal-grid">
      ${['L','M','M','J','V','S','D'].map(d=>`<div class="mini-cal-day-label">${d}</div>`).join('')}
  `;

  // Cases vides avant le 1er
  for(let i=0;i<startDow;i++) html += '<div></div>';

  for(let d=1;d<=lastDay.getDate();d++){
    const dateStr = miniCalYear+'-'+String(miniCalMonth+1).padStart(2,'0')+'-'+String(d).padStart(2,'0');
    const isToday = dateStr === todayStr;
    const isCurWeek = curWeekDates.has(dateStr);
    const hasMission = missionDates.has(dateStr);
    const cls = [
      'mini-cal-day',
      isToday ? 'today' : '',
      isCurWeek && !isToday ? 'cur-week' : '',
      hasMission ? 'has-mission' : '',
    ].filter(Boolean).join(' ');
    html += `<div class="${cls}" onclick="miniCalClick('${dateStr}')" title="${dateStr}">${d}</div>`;
  }

  html += '</div>';
  container.innerHTML = html;
}

function miniCalNav(dir){
  miniCalMonth += dir;
  if(miniCalMonth>11){ miniCalMonth=0; miniCalYear++; }
  if(miniCalMonth<0){ miniCalMonth=11; miniCalYear--; }
  renderMiniCal();
}

function miniCalClick(dateStr){
  // Naviguer vers la date cliquée dans le planning
  const d = new Date(dateStr + 'T00:00:00');
  calDate = d;
  calMonth = d.getMonth();
  calYear  = d.getFullYear();
  // Si on était en vue mois/année, passer en vue semaine
  if(calView === 'month' || calView === 'year' || calView === 'list'){
    calView = 'week';
    document.querySelectorAll('#tab-planning .filter-btn').forEach(b=>b.classList.remove('active'));
    const wb = document.getElementById('view-btn-week');
    if(wb) wb.classList.add('active');
  }
  renderCalendar();
  renderMiniCal(); // Mettre à jour la surbrillance
  console.log('[MiniCal] Navigation vers', dateStr);
}
function buildNav(){
  const nav = document.getElementById('main-nav');
  let tabs;
  if(currentUser.isAdmin){
    tabs = [
      {id:'dashboard',label:'📊 Dashboard'},
      {id:'planning',label:'📅 Planning'},
      {id:'recherche',label:'🔍 Recherche'},
      {id:'employes',label:'👷 Équipe'},
      {id:'clients',label:'🏢 Clients'},
      {id:'chat',label:'💬 Tchat'}
    ];
  } else if(currentUser.role === 'client'){
    tabs = [{id:'espace-client',label:'📋 Mes missions'}];
  } else {
    tabs = [
      {id:'dashboard',label:'📊 Résumé'},
      {id:'planning',label:'📅 Mes missions'},
      {id:'recherche',label:'🔍 Recherche'},
      {id:'chat',label:'💬 Tchat'}
    ];
  }
  const defaultTab = tabs[0].id;
  nav.innerHTML = tabs.map(t=>`<button class="nav-btn${t.id===defaultTab?' active':''}" onclick="showTab('${t.id}',this)">${t.label}</button>`).join('');
  document.getElementById('refresh-bar').style.display = (currentUser.role==='client') ? 'none' : 'block';
  // Render initial tab content
  if(currentUser.role === 'client'){
    renderEspaceClient();
  }
}

async function refreshMissions(){
  showToast('Actualisation en cours...');
  await loadMissionsFromSheets();
  showToast('✅ Missions mises à jour !');
}

function showTab(id, btn){
  document.querySelectorAll('.tab-content').forEach(t=>t.classList.remove('active'));
  document.querySelectorAll('.nav-btn').forEach(b=>b.classList.remove('active'));
  document.getElementById('tab-'+id).classList.add('active');
  if(btn) btn.classList.add('active');
  const contentEl = document.querySelector('.content');
  if(id === 'planning'){
    contentEl.classList.add('planning-active');
    renderCalendar();
  } else {
    contentEl.classList.remove('planning-active');
    if(id==='employes') renderEmployes();
    if(id==='dashboard') renderDashboard();
    if(id==='recherche'){ document.getElementById('search-input').focus(); doSearch(''); }
    if(id==='clients') renderClients();
    if(id==='espace-client') renderEspaceClient();
    if(id==='chat') renderChatTab();
  }
}

// ══ RENDER ALL ════════════════════════════════════════════════════════════════
function renderAll(options){
  options = options || {};
  renderDashboard();
  if(!calView) calView = 'week';

  // ★ Pour les monteurs : pointer vers la mission la plus proche
  if(currentUser && !currentUser.isAdmin && currentUser.role !== 'client'){
    const myM = getMyMissions();
    if(myM.length > 0){
      const today = new Date();
      const nearest = myM.slice().sort((a,b)=>
        Math.abs(new Date(a.date)-today) - Math.abs(new Date(b.date)-today)
      )[0];
      if(nearest && nearest.date){
        const mDate = new Date(nearest.date + 'T00:00:00');
        calDate = mDate;
        calMonth = mDate.getMonth();
        calYear = mDate.getFullYear();
      }
    }
  }

  // ★ Si une mission vient d'être créée/modifiée, naviguer vers sa date
  if(options.missionDate){
    const mDate = new Date(options.missionDate + 'T00:00:00');
    calDate = mDate;
    calMonth = mDate.getMonth();
    calYear = mDate.getFullYear();
    console.log('[Planning] Navigation vers', options.missionDate);
  }

  renderCalendar();
  if(currentUser.isAdmin) renderEmployes();
  if(currentUser.isAdmin) renderClients();
  // ★ Pour le client : ne re-render l'espace que si l'onglet est actif
  // Évite de réinitialiser la barre de recherche à chaque auto-refresh
  if(currentUser.role === 'client'){
    const tab = document.getElementById('tab-espace-client');
    if(tab && tab.classList.contains('active')) renderEspaceClient();
  }
  document.getElementById('m-prix-group').style.display = currentUser.isAdmin?'':'none';
  document.getElementById('m-facture-group').style.display = currentUser.isAdmin?'':'none';
  document.getElementById('ca-card').style.display = currentUser.isAdmin?'':'none';
  populateClientDropdown();
}

// ══ DASHBOARD ═════════════════════════════════════════════════════════════════
function renderDashboard(){
  // ★ Afficher/masquer le bouton de calibration selon le rôle
  var calBtn = document.getElementById('admin-calibration-btn');
  if(calBtn) calBtn.style.display = (currentUser && currentUser.isAdmin) ? 'block' : 'none';

  const now = new Date();
  let myMissions;
  if(currentUser.isAdmin){
    myMissions = missions;
  } else if(currentUser.role === 'client'){
    myMissions = missions.filter(m=>parseInt(m.clientId)===parseInt(currentUser.id));
  } else {
    // Monteur — même logique que getMyMissions avec possibleIds
    const uid = parseInt(currentUser.id);
    const uLogin = (currentUser.login||'').toLowerCase();
    const possibleIds = new Set([uid]);
    const emp = employees.find(e=>parseInt(e.id)===uid||(e.login||'').toLowerCase()===uLogin);
    if(emp) possibleIds.add(parseInt(emp.id));
    const u = USERS.find(u=>(u.login||'').toLowerCase()===uLogin);
    if(u) possibleIds.add(parseInt(u.id));
    myMissions = missions.filter(m=>Array.isArray(m.monteurs)&&m.monteurs.some(mid=>possibleIds.has(parseInt(mid)))&&m.statut!=='annule');
  }
  const thisMo = myMissions.filter(m=>{const d=new Date(m.date);return d.getMonth()===now.getMonth()&&d.getFullYear()===now.getFullYear()});
  document.getElementById('stat-total').textContent = thisMo.length;
  document.getElementById('stat-confirme').textContent = thisMo.filter(m=>m.statut==='confirme').length;
  document.getElementById('stat-attente').textContent = thisMo.filter(m=>m.statut==='en_attente').length;
  document.getElementById('stat-termine').textContent = thisMo.filter(m=>m.statut==='termine').length;
  if(currentUser.isAdmin) renderCA();
  // Afficher les missions récentes (7 derniers jours) + à venir
  const sevenDaysAgo = new Date(); sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
  const upcoming = myMissions
    .filter(m=>new Date(m.date)>=sevenDaysAgo && m.statut!=='annule')
    .sort((a,b)=>a.date>b.date?1:-1)
    .slice(0,5);
  const el = document.getElementById('upcoming-missions');
  if(!upcoming.length){el.innerHTML='<p style="color:var(--grey);font-size:.85rem;text-align:center;padding:.5rem">Aucune mission récente ou à venir</p>';return}
  el.innerHTML = upcoming.map(m=>missionCard(m,true)).join('');
}

function renderCA(){
  const now = new Date();
  let filtered=[], labels=[];
  if(caPeriod==='mois'){
    filtered=missions.filter(m=>{const d=new Date(m.date);return d.getMonth()===now.getMonth()&&d.getFullYear()===now.getFullYear()&&m.statut!=='annule'});
    for(let w=1;w<=4;w++){labels.push('S'+w);} 
    const vals=[0,0,0,0];
    filtered.forEach(m=>{const d=new Date(m.date);const w=Math.min(3,Math.floor((d.getDate()-1)/7));vals[w]+=(m.prix||0)});
    renderBars(vals,labels);
    document.getElementById('ca-val').textContent=(filtered.reduce((s,m)=>s+(m.prix||0),0)).toLocaleString('fr-FR')+' €';
  } else if(caPeriod==='trimestre'){
    const q=Math.floor(now.getMonth()/3);
    const months=['Jan','Fév','Mar','Avr','Mai','Juin','Juil','Août','Sep','Oct','Nov','Déc'];
    labels=[months[q*3],months[q*3+1],months[q*3+2]];
    const vals=[0,0,0];
    missions.filter(m=>m.statut!=='annule').forEach(m=>{const d=new Date(m.date);if(Math.floor(d.getMonth()/3)===q&&d.getFullYear()===now.getFullYear()){vals[d.getMonth()-q*3]+=(m.prix||0)}});
    renderBars(vals,labels);
    document.getElementById('ca-val').textContent=vals.reduce((s,v)=>s+v,0).toLocaleString('fr-FR')+' €';
  } else {
    const months=['J','F','M','A','M','J','J','A','S','O','N','D'];
    labels=months;
    const vals=new Array(12).fill(0);
    missions.filter(m=>m.statut!=='annule'&&new Date(m.date).getFullYear()===now.getFullYear()).forEach(m=>{vals[new Date(m.date).getMonth()]+=(m.prix||0)});
    renderBars(vals,labels);
    document.getElementById('ca-val').textContent=vals.reduce((s,v)=>s+v,0).toLocaleString('fr-FR')+' €';
  }
}

function renderBars(vals,labels){
  const max=Math.max(...vals,1);
  document.getElementById('ca-bars').innerHTML=vals.map((v,i)=>`<div class="bar" style="height:${Math.max(4,v/max*76)}px" title="${v.toLocaleString('fr-FR')} €"><span class="bar-val">${v>0?v.toLocaleString('fr-FR')+'€':''}</span></div>`).join('');
  document.getElementById('ca-bar-labels').innerHTML=labels.map(l=>`<div style="flex:1;text-align:center;font-size:.65rem;color:var(--grey)">${l}</div>`).join('');
}

function setCAPeriod(p,btn){
  caPeriod=p;document.querySelectorAll('#ca-card .filter-btn').forEach(b=>b.classList.remove('active'));btn.classList.add('active');renderCA();
}

// ══ PLANNING ══════════════════════════════════════════════════════════════════
let calView = 'week';
let calDate = new Date(); // current reference date

function getMyMissions(){
  if(currentUser.isAdmin) return missions;
  if(currentUser.role === 'client') return missions.filter(m=>parseInt(m.clientId)===parseInt(currentUser.id));

  const uid = parseInt(currentUser.id);
  const uLogin = (currentUser.login||'').toLowerCase();
  const uNom = (currentUser.nom||'').toLowerCase();

  // Trouver l'employee correspondant pour avoir tous ses identifiants
  const emp = employees.find(e=>
    parseInt(e.id)===uid ||
    (e.login||'').toLowerCase()===uLogin ||
    (e.nom||'').toLowerCase()===uNom
  );
  // Liste de tous les IDs possibles pour ce monteur
  const possibleIds = new Set();
  possibleIds.add(uid);
  if(emp) possibleIds.add(parseInt(emp.id));
  // Chercher aussi dans USERS
  const userEntry = USERS.find(u=>(u.login||'').toLowerCase()===uLogin);
  if(userEntry) possibleIds.add(parseInt(userEntry.id));

  console.log('[Missions] ══════════════════════════════════');
  console.log('[Missions] Monteur:', currentUser.nom, '| login:', uLogin);
  console.log('[Missions] IDs possibles:', [...possibleIds].join(', '));
  console.log('[Missions] Employee Sheets trouvé:', emp ? emp.nom + ' id:' + emp.id : '❌ INTROUVABLE');
  console.log('[Missions] Total missions:', missions.length);

  const result = missions.filter(function(m){
    if(!Array.isArray(m.monteurs)) return false;
    // ★ CORRECTION : le monteur voit TOUTES ses missions sauf "annule"
    // "en_attente" était exclu par erreur — c'est justement quand la mission vient d'être créée
    const found = m.monteurs.some(function(mid){
      return possibleIds.has(parseInt(mid));
    });
    if(found) console.log('[Missions]  ✅', m.client, m.date, '| statut:', m.statut, '| monteurs:', m.monteurs);
    return found && m.statut !== 'annule';
  });

  console.log('[Missions] Missions filtrées:', result.length);
  if(result.length === 0 && missions.length > 0){
    console.log('[Missions] ⚠️ AUCUNE MISSION — Vérif des IDs dans les missions:');
    missions.slice(0,3).forEach(m=>console.log('  Mission', m.id, m.client, '| monteurs:', JSON.stringify(m.monteurs)));
  }
  console.log('[Missions] ══════════════════════════════════');
  return result;
}

function setView(v, btn){
  calView = v;
  document.querySelectorAll('#tab-planning .filter-btn').forEach(function(b){ b.classList.remove('active'); });
  if(btn) btn.classList.add('active');
  renderCalendar();
}

function goToday(){
  calDate = new Date();
  calMonth = calDate.getMonth();
  calYear = calDate.getFullYear();
  renderCalendar();
}

function changeMonth(dir){
  if(calView === 'day'){
    calDate = new Date(calDate.getFullYear(), calDate.getMonth(), calDate.getDate() + dir);
  } else if(calView === 'week'){
    calDate = new Date(calDate.getFullYear(), calDate.getMonth(), calDate.getDate() + dir*7);
  } else if(calView === 'year'){
    calDate = new Date(calDate.getFullYear() + dir, calDate.getMonth(), 1);
  } else {
    calMonth += dir;
    if(calMonth > 11){ calMonth = 0; calYear++; }
    if(calMonth < 0){ calMonth = 11; calYear--; }
    calDate = new Date(calYear, calMonth, 1);
  }
  calMonth = calDate.getMonth();
  calYear = calDate.getFullYear();
  renderCalendar();
}

function renderCalendar(){
  renderMiniCal(); // Sync mini calendrier
  const months = ['Janvier','Février','Mars','Avril','Mai','Juin','Juillet','Août','Septembre','Octobre','Novembre','Décembre'];


  // Update label
  const label = document.getElementById('cal-month-label');
  if(calView === 'day'){
    label.textContent = calDate.toLocaleDateString('fr-FR',{weekday:'long',day:'numeric',month:'long',year:'numeric'});
  } else if(calView === 'week'){
    const mon = getMonday(calDate);
    const sun = new Date(mon); sun.setDate(sun.getDate()+6);
    label.textContent = mon.toLocaleDateString('fr-FR',{day:'numeric',month:'short'}) + ' - ' + sun.toLocaleDateString('fr-FR',{day:'numeric',month:'short',year:'numeric'});
  } else if(calView === 'year'){
    label.textContent = calDate.getFullYear();
  } else {
    label.textContent = months[calMonth] + ' ' + calYear;
  }

  if(calView === 'month') renderMonthView();
  else if(calView === 'week') {
    // ★ Sur mobile, vue agenda style Google Calendar au lieu de la grille horaire serrée
    if(window.innerWidth <= 599) renderMobileAgendaWeek();
    else renderWeekView();
  }
  else if(calView === 'day') {
    if(window.innerWidth <= 599) renderMobileAgendaDay();
    else renderDayView();
  }
  else if(calView === 'year') renderYearView();
  else renderListView();
}

