// ══ MISSIONS ══════════════════════════════════════════════════════════════════
function statusBadge(s){
  const map={en_attente:['badge-orange','En attente'],confirme:['badge-blue','Confirmée'],facture:['badge-green','Facturée 🧾'],en_cours:['badge-blue','En cours'],termine:['badge-green','Terminée'],annule:['badge-red','Annulée']};
  const [cls,label]=map[s]||['badge-grey',s];
  return `<span class="badge ${cls}">${label}</span>`;
}

function missionCard(m, compact=false){
  const monteurNames=m.monteurs.map(id=>{const e=employees.find(e=>e.id===id);return e?e.nom.split(' ')[0]:''}).filter(Boolean).join(', ');
  const mapsUrl=`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(m.adresse)}`;
  const wazeUrl=`https://waze.com/ul?q=${encodeURIComponent(m.adresse)}`;
  const prixHtml=currentUser.isAdmin&&m.prix?`<span class="mission-prix">${m.prix.toLocaleString('fr-FR')} € HT</span>`:'';
  return `<div class="mission-item status-${m.statut}" onclick="openDetailModal(${m.id})" style="cursor:pointer;border-left:5px solid ${m.color||'var(--copper)'}"> <div class="mission-header"> <span class="mission-client">${m.client}</span>
      ${statusBadge(m.statut)} </div> <div class="mission-date">📅 ${new Date(m.date+'T00:00').toLocaleDateString('fr-FR',{weekday:'short',day:'numeric',month:'short'})} à ${m.heure}</div> <a class="mission-addr" href="${mapsUrl}" target="_blank">📍 ${m.adresse}</a>
    ${m.tel?`<a class="mission-tel" href="tel:${m.tel}">📞 ${m.tel}</a>`:''}
    ${m.desc?`<div class="mission-desc">${m.desc}</div>`:''} <div class="mission-footer"> <div>
        ${prixHtml}
        ${monteurNames?`<div class="mission-monteurs">👷 ${monteurNames} · 🚛 ${m.camions} camion(s)</div>`:''} </div>
      ${!compact&&currentUser.isAdmin?`<div class="mission-actions" style="flex-wrap:wrap;gap:.3rem"> <button class="btn btn-ghost btn-sm" onclick="editMission(${m.id})">✏️</button> <button class="btn btn-danger btn-sm" onclick="deleteMission(${m.id})">🗑️</button> <button class="btn btn-ghost btn-sm" style="background:#F7F4F1;border-color:var(--copper);color:var(--copper-dk);flex:1" onclick="generatePDFReport(${m.id})">📄 Rapport PDF</button>
        ${m.lmBon?`<button class="btn btn-ghost btn-sm" style="width:100%;background:#E8F5E9;color:#007A33;border-color:#007A33" onclick="downloadExistingLMBon(${m.id})">📋 Télécharger le bon Leroy Merlin</button>`:''} </div>`:''}
      ${!compact&&!currentUser.isAdmin&&m.statut!=='termine'?`<div class="mission-actions" style="flex-direction:column;gap:.4rem"> <button class="btn btn-primary btn-sm" style="width:100%" onclick="openUploadModal(${m.id})">📎 Ajouter photos / documents</button>
        ${isLeroyMerlinMission(m)?`<button class="btn btn-ghost btn-sm" style="width:100%;background:#E8F5E9;color:#007A33;border-color:#007A33" onclick="openLMModal(${m.id})">📋 Bon de réception Leroy Merlin</button>`:''} <button class="btn btn-ghost btn-sm" style="width:100%;background:#EAF7EF;color:#1E8449;border-color:#1E8449" onclick="completeMission(${m.id})">✅ Terminer l'intervention</button> </div>`:''}
      ${m.signature?`<div style="margin-top:.5rem;padding:.4rem .6rem;background:#EAF7EF;border-radius:6px;font-size:.78rem;color:#1E8449">✅ Signé le ${m.signature.date}</div>`:''}
      ${m.attachments&&m.attachments.length?`<div style="margin-top:.6rem"> <div style="font-size:.78rem;font-weight:600;color:var(--grey);margin-bottom:.3rem">📎 ${m.attachments.length} fichier(s) joint(s)</div>
        ${m.attachments.map(a=>{
          const isImg=(a.type&&a.type.startsWith('image/'))||/\.(jpg|jpeg|png|gif|webp)$/i.test(a.name||'');
          const icon=isImg?'🖼️':/\.pdf$/i.test(a.name||'')?'📄':'📁';
          return `<div style="display:flex;align-items:center;gap:.4rem;padding:.3rem 0;border-bottom:1px solid var(--border)"> <span>${icon}</span> <span style="flex:1;font-size:.8rem;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${a.name||'Fichier'}</span> <a href="${a.url}" target="_blank" style="background:var(--copper);color:white;border-radius:5px;padding:.2rem .45rem;font-size:.72rem;text-decoration:none;flex-shrink:0">Ouvrir</a> <a href="${a.url}" download="${a.name||'fichier'}" style="background:var(--dark);color:white;border-radius:5px;padding:.2rem .45rem;font-size:.72rem;text-decoration:none;flex-shrink:0">⬇️</a> </div>`;
        }).join('')} </div>`:''} </div> </div>`;
}

