// ══ MODAL MISSION ═════════════════════════════════════════════════════════════
function openMissionModal(m=null){
  editingMissionId=m?m.id:null;
  // ★ Reset uploadingMissionId — évite que les fichiers d'une mission collent à la suivante
  if(!m) uploadingMissionId = null;
  const titleEl = document.getElementById('mission-modal-title');
  if(titleEl) titleEl.textContent=m?'Modifier la mission':'Nouvelle mission';
  document.getElementById('m-client').value=m?m.client:'';
  document.getElementById('m-date').value=m?m.date:'';
  document.getElementById('m-heure').value=m?m.heure:'08:00';
  document.getElementById('m-heure-fin').value=m?m.heureFin:'17:00';
  document.getElementById('m-color').value=m?m.color||'#D4956A':'#D4956A';
  document.getElementById('m-adresse').value=m?m.adresse:'';
  document.getElementById('m-facture').value=m?m.factureNum||'':'';
  // Reset color picker
  document.querySelectorAll('#m-color-picker div').forEach(d=>{
    d.style.border = d.style.background===(m?m.color||'#D4956A':'#D4956A') ? '3px solid #333' : '3px solid transparent';
  });
  document.getElementById('m-tel').value=m?m.tel:'';
  document.getElementById('m-desc').value=m?m.desc:'';
  document.getElementById('m-prix').value=m?m.prix:'';
  document.getElementById('m-statut').value=m?m.statut:'en_attente';
  document.getElementById('m-camions').value=m?m.camions:1;
  // Set client link dropdown
  populateClientDropdown(m?m.clientId:null);
  // ★ Case Leroy Merlin (auto-détectée via le client lié)
  const lmHidden = document.getElementById('m-is-lm');
  const lmIndicator = document.getElementById('m-lm-indicator');
  const isLMNow = m ? (m.isLM === true) : false;
  if(lmHidden) lmHidden.value = isLMNow ? 'true' : '';
  if(lmIndicator) lmIndicator.style.display = isLMNow ? 'flex' : 'none';
  const listEl=document.getElementById('m-monteurs-list');
  // ★ actif===false explicitement — undefined/null/true = actif
  const activeMonteurs = employees.filter(e=>e.actif!==false);
  console.log('[Modal] Monteurs disponibles:', activeMonteurs.length, activeMonteurs.map(e=>e.nom+'(id:'+e.id+')').join(', '));
  listEl.innerHTML=activeMonteurs.map(e=>` <label class="check-item"> <input type="checkbox" value="${e.id}" ${m&&m.monteurs&&m.monteurs.some(mid=>parseInt(mid)===parseInt(e.id))?'checked':''}>
      ${e.nom} <span style="color:var(--grey);font-size:.8rem">(${e.role})</span> </label>`).join('');
  document.getElementById('mission-modal').style.display='flex';
}

function editMission(id){
  const m=missions.find(m=>m.id===id);
  if(m)openMissionModal(m);
}

function closeMissionModal(){
  document.getElementById('mission-modal').style.display='none';
  editingMissionId = null;
  duplicatingFrom = null;
  // Clean up duplicate banner if present
  var banner = document.getElementById('duplicate-banner');
  if(banner) banner.remove();
  // Reset date border
  var dateEl = document.getElementById('m-date');
  if(dateEl) dateEl.style.border = '';
}

function shakeMissionModal(event){
  // Only shake if clicking directly on the overlay (not inside the modal)
  if(event && event.target !== document.getElementById('mission-modal')) return;
  var modal = document.querySelector('#mission-modal .modal');
  if(!modal) return;
  modal.style.animation = 'shake .3s ease';
  setTimeout(function(){ modal.style.animation = ''; }, 350);
}

function saveMission(){
  const client=document.getElementById('m-client').value.trim()||'Sans titre';
  const date=document.getElementById('m-date').value;
  const adresse=document.getElementById('m-adresse').value.trim();
  // Date is always required
  if(!date){
    var dateEl=document.getElementById('m-date');
    if(dateEl){dateEl.style.border='2px solid var(--danger)';dateEl.focus();}
    showToast('⚠️ La date est obligatoire');return;
  }
  const monteurs=[...document.querySelectorAll('#m-monteurs-list input:checked')].map(i=>parseInt(i.value));
  const clientLinkEl = document.getElementById('m-client-link');
  const clientIdVal = clientLinkEl ? (parseInt(clientLinkEl.value)||null) : null;
  const lmHiddenEl = document.getElementById('m-is-lm');
  const isLMVal = lmHiddenEl ? (lmHiddenEl.value === 'true') : false;
  const mission={
    client, date,
    heure:document.getElementById('m-heure').value,
    heureFin:document.getElementById('m-heure-fin').value,
    color:document.getElementById('m-color').value||'#D4956A',
    adresse,
    tel:document.getElementById('m-tel').value,
    desc:document.getElementById('m-desc').value,
    statut:document.getElementById('m-statut').value,
    prix:parseFloat(document.getElementById('m-prix').value)||0,
    factureNum:document.getElementById('m-facture').value||'',
    monteurs,
    camions:parseInt(document.getElementById('m-camions').value)||1,
    clientId: clientIdVal,
    isLM: isLMVal,
    fichier:null
  };
  if(editingMissionId){
    const idx=missions.findIndex(m=>m.id===editingMissionId);
    missions[idx]={...missions[idx],...mission};
    console.log('[saveMission] Mission modifiée id:', editingMissionId, '| monteurs:', JSON.stringify(mission.monteurs));
    showToast('Mission mise à jour ✓');
  } else {
    mission.id=nextMissionId++;
    missions.push(mission);
    console.log('[saveMission] Nouvelle mission id:', mission.id, '| client:', mission.client, '| monteurs:', JSON.stringify(mission.monteurs));
    // Vérif : les IDs des monteurs existent-ils dans employees ?
    mission.monteurs.forEach(mid=>{
      const emp = employees.find(e=>parseInt(e.id)===parseInt(mid));
      if(emp) console.log('[saveMission]  ✅ Monteur trouvé:', emp.nom, 'id:', emp.id);
      else console.log('[saveMission]  ❌ Monteur id:', mid, '— INTROUVABLE dans employees !');
    });
    showToast('Mission créée ✓');
  }
  duplicatingFrom = null;
  const savedDate = mission.date;
  closeMissionModal();
  saveMissionsToSheets();
  // ★ Naviguer vers la date de la mission créée/modifiée
  renderAll({missionDate: savedDate});
}

function deleteMission(id){
  if(!confirm('Supprimer cette mission ?'))return;
  missions=missions.filter(m=>m.id!==id);
  saveMissionsToSheets();
  renderAll();
  showToast('Mission supprimée');
}

// ══ EMPLOYES ══════════════════════════════════════════════════════════════════
function initials(nom){return nom.split(' ').map(n=>n[0]).join('').substring(0,2).toUpperCase()}

async function loadEmployees(){
  try {
    const res = await fetch(SHEETS_URL + '?action=load_employees');
    const text = await res.text();
    const raw = JSON.parse(text);
    // ★ Le Apps Script retourne maintenant {missions,clients,employees} même pour load_employees
    const data = Array.isArray(raw) ? raw : (raw.employees || []);
    if(data.length > 0) {
      // ★ NE PAS remplacer employees[] si les données Sheets ont des IDs différents
      // Fusionner par LOGIN (clé stable) en préservant les IDs statiques
      data.forEach(function(e){
        const eLogin = (e.login||'').toLowerCase();
        const existing = employees.find(emp=>(emp.login||'').toLowerCase()===eLogin);
        if(existing){
          // Mettre à jour pass et actif mais GARDER l'ID statique pour ne pas casser les missions
          existing.pass = e.pass || existing.pass;
          existing.actif = e.actif !== false;
          existing.nom = e.nom || existing.nom;
          existing.role = e.role || existing.role;
          // Sync USERS aussi
          const u = USERS.find(u=>(u.login||'').toLowerCase()===eLogin);
          if(u){ u.pass=existing.pass; u.actif=existing.actif; u.id=existing.id; }
          console.log('[Employees] Mis à jour:', existing.nom, 'id:', existing.id);
        } else {
          // Nouveau monteur ajouté via l'interface
          employees.push({id:e.id, nom:e.nom, role:e.role||'Monteur', login:e.login, pass:e.pass, actif:e.actif!==false});
          USERS.push({id:e.id, login:e.login, pass:e.pass, nom:e.nom||e.login, role:e.role||'Monteur', isAdmin:e.isAdmin===true, actif:e.actif!==false});
          console.log('[Employees] Nouveau:', e.nom, 'id:', e.id);
        }
      });
      nextEmpId = Math.max(...employees.map(e=>e.id), 9) + 1;
      console.log('[Employees] État final:', employees.map(e=>e.nom+'('+e.id+')').join(', '));
    }
  } catch(e) { console.log('[Employees] Erreur chargement:', e.message); }
}

async function saveEmployeesToSheets(){
  try {
    await fetch(SHEETS_URL, {
      method: 'POST',
      headers: {'Content-Type': 'text/plain'},
      body: JSON.stringify({action: 'save_employees', employees, clients, missions})
    });
    console.log('[Sheets] Employees sauvegardés ✅');
  } catch(e) { console.log('[Sheets] Erreur save employees:', e.message); }
}

function isHilel(){
  return currentUser && currentUser.login.toLowerCase() === 'hilel';
}

function renderEmployes(){
  const el=document.getElementById('employes-list');
  var addContainer = document.getElementById('add-emp-btn-container');
  if(addContainer){
    addContainer.innerHTML = currentUser.isAdmin
      ? '<button class="btn btn-primary btn-sm" onclick="openEmpModal()">+ Ajouter</button>'
      : '';
  }

  // Admins section
  const admins = USERS.filter(u=>u.isAdmin);
  let adminHtml = '<p style="font-size:.8rem;font-weight:600;color:var(--grey);margin-bottom:.5rem;text-transform:uppercase;letter-spacing:.05em">Administrateurs</p>';
  adminHtml += admins.map(a=>{
    const canDelete = isHilel() && a.login.toLowerCase() !== 'hilel';
    return ` <div class="emp-item" style="border-left:3px solid var(--copper)"> <div class="emp-avatar" style="background:var(--copper-dk)">${initials(a.nom)}</div> <div class="emp-info"> <div class="emp-name">${a.nom} <span class="badge badge-orange" style="font-size:.7rem">Admin</span></div> <div class="emp-role">@${a.login}</div> </div> <div class="emp-actions">
        ${isHilel() ? `<button class="btn btn-ghost btn-sm" onclick="openChangePassModal('admin',${a.id})" title="Changer mot de passe">🔑</button>` : ''}
        ${canDelete ? `<button class="btn btn-danger btn-sm" onclick="removeAdmin(${a.id})" title="Supprimer admin">🗑️</button>` : ''} </div> </div>`;
  }).join('');

  adminHtml += '<div style="height:.75rem"></div><p style="font-size:.8rem;font-weight:600;color:var(--grey);margin-bottom:.5rem;text-transform:uppercase;letter-spacing:.05em">Monteurs</p>';

  const monteurs = employees.filter(e=>!e.isAdmin);
  const monteursHtml = monteurs.map(e=>` <div class="emp-item" style="${e.actif===false?'opacity:.5':''}"> <div class="emp-avatar" style="${e.actif===false?'background:#aaa':''}">${initials(e.nom)}</div> <div class="emp-info"> <div class="emp-name">${e.nom} ${e.actif===false?'<span class="badge badge-grey" style="font-size:.7rem">Désactivé</span>':''}</div> <div class="emp-role">${e.role} · @${e.login}</div> </div> <div class="emp-actions"> <button class="btn btn-ghost btn-sm" onclick="openChangePassModal('monteur',${e.id})" title="Changer mot de passe">🔑</button> <button class="btn btn-ghost btn-sm" onclick="toggleEmpActive(${e.id})" title="${e.actif===false?'Réactiver':'Désactiver'}">${e.actif===false?'✅':'⏸️'}</button> <button class="btn btn-danger btn-sm" onclick="removeEmp(${e.id})" title="Supprimer">🗑️</button> </div> </div>`).join('');

  el.innerHTML = adminHtml + monteursHtml;
}

function openEmpModal(){
  document.getElementById('e-nom').value='';
  document.getElementById('e-login').value='';
  document.getElementById('e-pass').value='';
  document.getElementById('e-role').value='';
  document.getElementById('e-type').value='monteur';
  document.getElementById('e-role-group').style.display='block';
  // Only Hilel can create admins — hide the admin option for other admins
  var typeSelect = document.getElementById('e-type');
  var adminOption = typeSelect.querySelector('option[value="admin"]');
  if(adminOption) adminOption.style.display = isHilel() ? '' : 'none';
  document.getElementById('emp-modal').style.display='flex';
}
function closeEmpModal(){document.getElementById('emp-modal').style.display='none'}

async function saveEmp(){
  const nom=document.getElementById('e-nom').value.trim();
  const login=document.getElementById('e-login').value.trim().toLowerCase();
  const pass=document.getElementById('e-pass').value.trim();
  const role=document.getElementById('e-role').value||'Monteur';
  const type=document.getElementById('e-type').value;

  if(!nom||!login||!pass){showToast('Champs obligatoires manquants');return}
  if(employees.find(e=>e.login&&e.login.toLowerCase()===login)||USERS.find(u=>u.login.toLowerCase()===login)){
    showToast('Cet identifiant existe déjà');return;
  }
  if(pass.length < 6){showToast('Mot de passe trop court (6 caractères min)');return}

  // Security: only Hilel can create admins
  if(type==='admin' && !isHilel()){
    showToast('⛔ Seul Hilel peut créer un compte administrateur');return;
  }

  const newId = nextEmpId++;
  if(type==='admin'){
    const newAdmin={id:newId, login, pass, nom:nom.split(' ')[0], role:'admin', isAdmin:true, actif:true};
    // Add to USERS for immediate login availability
    USERS.push({...newAdmin});
    // Add to employees so it persists via Sheets
    employees.push({id:newId, nom, role:'Administrateur', login, pass, actif:true, isAdmin:true});
    await saveEmployeesToSheets();
    showToast('✅ Administrateur ajouté ! Il peut maintenant se connecter.');
  } else {
    const newEmp={id:newId, nom, role, login, pass, actif:true, isAdmin:false};
    employees.push(newEmp);
    // Also add to USERS so login works immediately
    USERS.push({id:newId, login, pass, nom:nom.split(' ')[0], role, isAdmin:false});
    await saveEmployeesToSheets();
    showToast('✅ Monteur ajouté !');
  }
  closeEmpModal();
  renderEmployes();
}

async function removeEmp(id){
  if(!confirm('Retirer cet employé ?'))return;
  employees=employees.filter(e=>e.id!==id);
  await saveEmployeesToSheets();
  renderEmployes();
  showToast('Employé retiré');
}

async function removeAdmin(id){
  if(!isHilel()){showToast('⛔ Action non autorisée');return;}
  const admin = USERS.find(u=>u.id===id);
  if(!admin){return;}
  if(admin.login.toLowerCase()==='hilel'){showToast('⛔ Impossible de supprimer le compte principal');return;}
  if(!confirm('Supprimer l\'admin ' + admin.nom + ' ?'))return;
  // Remove from USERS
  const idx = USERS.findIndex(u=>u.id===id);
  if(idx>-1) USERS.splice(idx,1);
  // Remove from employees if present
  employees = employees.filter(e=>e.id!==id);
  await saveEmployeesToSheets();
  renderEmployes();
  showToast('Administrateur supprimé');
}

async function toggleEmpActive(id){
  const emp = employees.find(e=>e.id===id);
  if(!emp) return;
  emp.actif = emp.actif === false ? true : false;
  // Also update USERS
  const user = USERS.find(u=>u.id===id);
  if(user) user.actif = emp.actif;
  await saveEmployeesToSheets();
  renderEmployes();
  showToast(emp.actif ? '✅ Compte réactivé' : '⏸️ Compte désactivé');
}

