let changePassTarget = null;

function openChangePassModal(type, id){
  changePassTarget = {type, id};
  document.getElementById('cp-pass').value = '';
  document.getElementById('cp-pass2').value = '';
  const name = type==='admin'
    ? USERS.find(u=>u.id===id)?.nom
    : employees.find(e=>e.id===id)?.nom;
  document.getElementById('cp-name-label').textContent = '👤 ' + (name||'Utilisateur');
  document.getElementById('changepass-modal').style.display = 'flex';
}

