function sendWhatsApp(id){
  const m = missions.find(function(m){return m.id===id});
  if(!m) return;
  const monteurNames = m.monteurs.map(function(mid){
    const e = employees.find(function(e){return e.id===mid});
    return e ? e.nom : '';
  }).filter(Boolean).join(', ');
  const dateStr = new Date(m.date+'T00:00').toLocaleDateString('fr-FR',{weekday:'long',day:'numeric',month:'long'});
  const nl = '%0A';
  const msg = encodeURIComponent('👷 *DESAEM — Mission du ') + dateStr + encodeURIComponent('*') + nl +
    nl +
    encodeURIComponent('🏗️ Client : ') + encodeURIComponent(m.client) + nl +
    encodeURIComponent('📅 Horaire : ') + encodeURIComponent(m.heure + (m.heureFin ? ' → ' + m.heureFin : '')) + nl +
    encodeURIComponent('📍 Adresse : ') + encodeURIComponent(m.adresse) + nl +
    (m.tel ? encodeURIComponent('📞 Tel : ') + encodeURIComponent(m.tel) + nl : '') +
    (m.desc ? encodeURIComponent('📝 ') + encodeURIComponent(m.desc) + nl : '') +
    nl +
    encodeURIComponent('👥 Équipe : ') + encodeURIComponent(monteurNames||'À définir') + nl +
    encodeURIComponent('🚛 Camions : ') + m.camions + nl +
    nl +
    encodeURIComponent('🔗 https://contactdesaem-del.github.io/Desaem-planning');
  window.open('https://wa.me/?text=' + msg, '_blank');
}

// ══ PASTE HANDLER ════════════════════════════════════════════════════════════
function handlePaste(e, el){
  e.preventDefault();
  var text = '';
  if(e.clipboardData){
    var html = e.clipboardData.getData('text/html');
    if(html){
      var tmp = document.createElement('div');
      tmp.innerHTML = html.replace(/<br[^>]*>/gi,'\n').replace(/<\/p>/gi,'\n').replace(/<\/div>/gi,'\n').replace(/<[^>]+>/g,'');
      text = (tmp.textContent || tmp.innerText || '').replace(/\n{3,}/g,'\n\n').trim();
    } else {
      text = e.clipboardData.getData('text/plain') || '';
    }
  } else {
    text = (window.clipboardData || {}).getData('Text') || '';
  }
  var s = el.selectionStart, en = el.selectionEnd, cur = el.value;
  el.value = cur.substring(0,s) + text + cur.substring(en);
  el.selectionStart = el.selectionEnd = s + text.length;
}

// ══ COPY TO CLIPBOARD ═════════════════════════════════════════════════════════
function copyToClipboard(text){
  navigator.clipboard.writeText(text).then(()=>{
    showToast('📋 Lien copié !');
  }).catch(()=>{
    // Fallback
    const el = document.createElement('textarea');
    el.value = text;
    document.body.appendChild(el);
    el.select();
    document.execCommand('copy');
    document.body.removeChild(el);
    showToast('📋 Lien copié !');
  });
}

// ══ QUICK SEARCH IN PLANNING ═════════════════════════════════════════════════
function doQuickSearch(query){
  var el = document.getElementById('quick-search-results');
  if(!el) return;
  query = (query||'').trim().toLowerCase();
  if(!query){ el.style.display='none'; return; }

  var myMissions = currentUser.isAdmin ? missions : missions.filter(function(m){
    const _uid=parseInt(currentUser.id);return Array.isArray(m.monteurs)&&m.monteurs.some(function(mid){return parseInt(mid)===_uid;});
  });
  var results = myMissions.filter(function(m){
    return [m.client||'',m.adresse||'',m.tel||'',m.desc||'',m.factureNum||'',m.date||''].join(' ').toLowerCase().indexOf(query) > -1;
  }).slice(0,8);

  el.innerHTML = '';

  if(!results.length){
    var noResult = document.createElement('div');
    noResult.style.cssText = 'padding:.5rem;color:var(--grey);font-size:.82rem;text-align:center';
    noResult.textContent = 'Aucun résultat';
    el.appendChild(noResult);
    el.style.display = 'block';
    return;
  }

  results.forEach(function(m){
    var color = m.color || 'var(--copper)';
    var dateStr = m.date ? new Date(m.date+'T00:00').toLocaleDateString('fr-FR',{day:'numeric',month:'short'}) : '';
    var item = document.createElement('div');
    item.style.cssText = 'display:flex;align-items:center;gap:.5rem;padding:.4rem .5rem;border-radius:6px;cursor:pointer;margin-bottom:2px';
    item.onmouseover = function(){ item.style.background='var(--light)'; };
    item.onmouseout = function(){ item.style.background='transparent'; };
    item.onclick = function(){
      el.style.display = 'none';
      var searchEl = document.getElementById('planning-search');
      if(searchEl) searchEl.value = '';
      openDetailModal(m.id);
    };
    var dot = document.createElement('span');
    dot.style.cssText = 'width:10px;height:10px;border-radius:50%;background:'+color+';flex-shrink:0';
    var info = document.createElement('div');
    info.style.cssText = 'flex:1;overflow:hidden';
    info.innerHTML = '<div style="font-size:.82rem;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+m.client+'</div><div style="font-size:.72rem;color:var(--grey)">'+dateStr+' · '+m.heure+'</div>';
    item.appendChild(dot);
    item.appendChild(info);
    el.appendChild(item);
  });

  el.style.display = 'block';

  document.addEventListener('click', function handler(e){
    if(!el.contains(e.target) && e.target.id !== 'planning-search'){
      el.style.display = 'none';
      document.removeEventListener('click', handler);
    }
  });
}

