// ══ RECHERCHE ═════════════════════════════════════════════════════════════════
function doSearch(query){
  var el = document.getElementById('search-results');
  if(!el) return;
  query = (query||'').trim().toLowerCase();

  if(!query){
    el.innerHTML = '<div style="text-align:center;color:var(--grey);padding:2rem;font-size:.9rem">Tapez un mot-clé pour rechercher une mission</div>';
    return;
  }

  var myMissions = currentUser.isAdmin ? missions : missions.filter(function(m){
    const _uid=parseInt(currentUser.id);return Array.isArray(m.monteurs)&&m.monteurs.some(function(mid){return parseInt(mid)===_uid;});
  });

  var results = myMissions.filter(function(m){
    var fields = [
      m.client||'',
      m.adresse||'',
      m.tel||'',
      m.desc||'',
      m.factureNum||'',
      m.date||'',
      m.heure||'',
      m.statut||''
    ].join(' ').toLowerCase();
    return fields.indexOf(query) > -1;
  });

  if(!results.length){
    el.innerHTML = '<div style="text-align:center;color:var(--grey);padding:2rem;font-size:.9rem">Aucune mission trouvée pour "<strong>' + query + '</strong>"</div>';
    return;
  }

  el.innerHTML = '<div style="font-size:.85rem;color:var(--grey);margin-bottom:.75rem">' + results.length + ' résultat(s) pour "' + query + '"</div>' +
    results.map(function(m){ return missionCard(m, false); }).join('');
}

