// ══ AUTO REFRESH ══════════════════════════════════════════════════════════════
let autoRefreshInterval = null;
let lastDataHash = '';
let lastChatHash = '';

function hashData(data){
  return JSON.stringify(data).length + '_' + (data.length || 0);
}

function startAutoRefresh(){
  if(autoRefreshInterval) clearInterval(autoRefreshInterval);
  autoRefreshInterval = setInterval(async()=>{
    if(!currentUser) return;

    // ★ Rattrapage automatique : si un bon Leroy Merlin n'a pas pu être synchronisé
    // tout à l'heure (connexion coupée), on retente discrètement ici
    if(pendingLMSyncMissionId){
      const ok = await saveMissionsToSheets();
      if(ok){
        showToast('✅ Bon de réception (resynchronisé) envoyé à l\'admin');
        pendingLMSyncMissionId = null;
      }
    }

    try {
      const res = await fetch(SHEETS_URL + '?t=' + Date.now());
      const text = await res.text();
      const data = JSON.parse(text);

      // ★ Gérer les deux formats : tableau (ancien) ET objet (nouveau Apps Script)
      let newMissions = null;
      if(Array.isArray(data)){
        newMissions = data;
      } else if(data && Array.isArray(data.missions)){
        newMissions = data.missions;
        // Mettre à jour clients si présents
        if(Array.isArray(data.clients) && data.clients.length > 0){
          clients = data.clients;
          syncClientsToUsers();
        }
        // Fusionner employees sans écraser les IDs statiques
        if(Array.isArray(data.employees) && data.employees.length > 0){
          data.employees.forEach(function(e){
            const eLogin = (e.login||'').toLowerCase();
            const existing = employees.find(emp=>(emp.login||'').toLowerCase()===eLogin);
            if(existing){ existing.pass=e.pass||existing.pass; existing.actif=e.actif!==false; }
            else if(e.login){ employees.push({id:e.id,nom:e.nom,role:e.role||'Monteur',login:e.login,pass:e.pass,actif:e.actif!==false}); }
          });
        }
      }

      if(Array.isArray(data.chatMessages)){
        const newChatHash = JSON.stringify(data.chatMessages);
        if(newChatHash !== lastChatHash){
          lastChatHash = newChatHash;
          chatMessages = data.chatMessages;
          nextChatMsgId = Math.max(...chatMessages.map(c=>c.id||0), 0) + 1;
          // Re-render le tchat seulement si l'onglet est actif, sans toast pour ne pas spammer
          const chatTab = document.getElementById('tab-chat');
          if(chatTab && chatTab.classList.contains('active')) renderChatTab(true);
        }
      }

      if(newMissions){
        const newHash = JSON.stringify(newMissions);
        if(newHash !== lastDataHash){
          console.log('[AutoRefresh] Nouvelles données détectées — missions:', newMissions.length);
          // ★ Notifier les nouvelles missions assignées à l'utilisateur courant
          if(lastDataHash && currentUser && !currentUser.isAdmin){
            const oldIds = new Set(missions.map(m=>m.id));
            newMissions.forEach(m => {
              const assignes = Array.isArray(m.assignes) ? m.assignes : (m.assigne ? [m.assigne] : []);
              const meConcerne = assignes.some(a =>
                String(a) === String(currentUser.id) ||
                String(a).toLowerCase() === String(currentUser.nom).toLowerCase()
              );
              if(!oldIds.has(m.id) && meConcerne){
                notifyNewMission(m);
              }
            });
          }
          lastDataHash = newHash;
          missions = newMissions;
          nextMissionId = Math.max(...missions.map(m=>m.id||0), 0) + 1;
          renderAll();
          showToast('\u{1F504} Planning mis à jour');
        }
      }
    } catch(e){ console.log('[AutoRefresh] Erreur:', e.message); }
  }, 5000);
}

