  preview.innerHTML = '';
  [...input.files].forEach(f=>{
    const span = document.createElement('span');
    span.style.cssText = 'background:var(--light);border:1px solid var(--border);border-radius:6px;padding:.25rem .6rem;font-size:.8rem;color:var(--dark)';
    span.textContent = '📄 ' + f.name;
    preview.appendChild(span);
  });
