const IMGBB_KEY = '2742fcdf6c38011943a7a7a3d8138cf2';

async function uploadFiles(){
  const input = document.getElementById('upload-file');
  if(!input.files.length){showToast('Sélectionne un fichier');return}
  const progress = document.getElementById('upload-progress');
  progress.style.display = 'block';
  progress.textContent = '⏳ Envoi en cours...';
  const mission = missions.find(m=>m.id===uploadingMissionId);
  if(!mission){showToast('Mission introuvable');return;}
  if(!mission.attachments) mission.attachments = [];

  let success = 0;
  let errors = [];
  const totalFiles = input.files.length;
 for(let i = 0; i < input.files.length; i++){
    const file = input.files[i];
    progress.textContent = '⏳ Envoi ' + (i+1) + '/' + totalFiles + ' : ' + file.name;
    try {
      const base64 = await fileToBase64(file);
      const isImage = file.type.startsWith('image/');
      let fileUrl = '';
      let fileName = file.name;

      if(isImage){
        const formData = new FormData(); formData.append('key', IMGBB_KEY); formData.append('image', base64); formData.append('name', file.name);
        const res = await fetch('https://api.imgbb.com/1/upload', {method:'POST', body:formData});
        const data = await res.json();
        if(data.success && data.data && data.data.url){
          fileUrl = data.data.display_url || data.data.url;
          fileName = data.data.title || file.name;
          success++;
        } else {
          errors.push(file.name + ': erreur ImgBB');
          console.error('[Upload] ImgBB error:', data);
          continue;
        }
      } else {
        // PDF via Google Apps Script (note: no-cors won't give response body)
        // Use a regular fetch with CORS to get the response
        try {
          const res = await fetch(SHEETS_URL, {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({
              action: 'upload_file',
              fileName: file.name,
              mimeType: file.type,
              fileData: base64,
              missionId: uploadingMissionId,
              uploadedBy: currentUser.nom
            })
          });
          const data = await res.json();
          if(data.fileUrl){
            fileUrl = data.fileUrl;
            success++;
          } else {
            errors.push(file.name + ': ' + (data.error||'erreur serveur'));
            continue;
          }
        } catch(corsErr){
          // Fallback: store as data URI if CORS blocks (not ideal but keeps data)
          console.warn('[Upload] PDF via Sheets failed, storing locally:', corsErr);
          errors.push(file.name + ': impossible d\'uploader (CORS). Contactez l\'admin.');
          continue;
        }
      }

      mission.attachments.push({ name: fileName,
        url: fileUrl,
        by: currentUser.nom,
        date: new Date().toLocaleDateString('fr-FR'),
        time: new Date().toLocaleTimeString('fr-FR',{hour:'2-digit',minute:'2-digit'}), type: file.type
      });
    } catch(e){
      errors.push(file.name + ': ' + e.message);
      console.error('[Upload] Error:', e);
    }
  }

  if(success > 0){
    progress.textContent = '💾 Sauvegarde sur le serveur...';
    await saveMissionsToSheets();
    // Force all clients to refresh (reset hash)
    lastDataHash = '';
    progress.style.display = 'none';
    closeUploadModal();
    // Refresh to confirm data is synced
    await loadMissionsFromSheets();
    showToast('✅ ' + success + ' fichier(s) envoyé(s) et sauvegardé(s) !');
    if(errors.length) showToast('⚠️ ' + errors.length + ' erreur(s) : ' + errors[0]);
  } else {
    progress.style.display = 'none';
    if(errors.length) showToast('❌ Erreur : ' + errors[0]);
    else showToast('❌ Aucun fichier envoyé');
  }
}

function fileToBase64(file){
  return new Promise((resolve, reject)=>{
    // Compress images before upload
    if(file.type.startsWith('image/')){
      const img = new window.Image();
      const url = URL.createObjectURL(file);
      img.onload = ()=>{
        const canvas = document.createElement('canvas');
        const MAX = 1200;
        let w = img.width, h = img.height;
        if(w > MAX){ h = Math.round(h * MAX / w); w = MAX; }
        if(h > MAX){ w = Math.round(w * MAX / h); h = MAX; }
        canvas.width = w; canvas.height = h;
        canvas.getContext('2d').drawImage(img, 0, 0, w, h);
        URL.revokeObjectURL(url);
        const b64 = canvas.toDataURL('image/jpeg', 0.7).split(',')[1];
        resolve(b64);
      };
      img.onerror = reject;
      img.src = url;
    } else {
      const reader = new FileReader();
      reader.onload = ()=> resolve(reader.result.split(',')[1]);
      reader.onerror = reject;
      reader.readAsDataURL(file);
    }
  });
}

