// ══ CHANGE STATUS (admin only) ═══════════════════════════════════════════════
async function changeStatus(id, newStatus){
  const m = missions.find(function(m){ return m.id === id; });
  if(!m || !currentUser.isAdmin) return;
  m.statut = newStatus;
  if(newStatus !== 'termine'){
    m.completedBy = null;
    m.completedAt = null;
  }
  await saveMissionsToSheets();
  renderAll();
  showToast('✅ Statut mis à jour !');
}

// ══ DUPLICATE MISSION ════════════════════════════════════════════════════════
function duplicateMission(id){
  const m = missions.find(function(m){ return parseInt(m.id) === parseInt(id); });
  if(!m) return;
  var copy = JSON.parse(JSON.stringify(m));
  // ★ Reset complet — nouvelle mission vierge sauf les infos de base
  copy.id = null; // sera assigné par nextMissionId
  copy.date = '';
  copy.heure = '';
  copy.heureFin = '';
  copy.statut = 'en_attente';
  copy.attachments = [];
  copy.comments = [];
  copy.signature = null;
  copy.lmBon = null;
  copy.completedBy = null;
  copy.completedAt = null;
  copy.completedTime = null;
  editingMissionId = null;
  duplicatingFrom = parseInt(id);
  openMissionModal(copy);
  setTimeout(function(){
    // Banner duplication
    var modal = document.getElementById('mission-modal');
    if(!modal) return;
    var existing = document.getElementById('duplicate-banner');
    if(existing) existing.remove();
    var banner = document.createElement('div');
    banner.id = 'duplicate-banner';
    banner.style.cssText = 'background:#FEF3CD;border:1px solid #F0C040;border-radius:8px;padding:.5rem .75rem;margin-bottom:.75rem;font-size:.82rem;color:#7B5800;display:flex;align-items:center;gap:.5rem';
    banner.innerHTML = '📋 <strong>Duplication</strong> — Modifiez la date puis cliquez sur Enregistrer.';
    var modalContent = modal.querySelector('.modal > div:last-child') || modal.querySelector('.modal');
    if(modalContent) modalContent.insertBefore(banner, modalContent.firstChild);
    var dateEl = document.getElementById('m-date');
    if(dateEl){ dateEl.style.border = '2px solid var(--copper)'; dateEl.focus(); }
    showToast('📋 Choisissez une nouvelle date');
  }, 100);
}

