// ══════════════════════════════════════════════════════════════════════════════
// ══ SIGNATURE ÉLECTRONIQUE ════════════════════════════════════════════════════
// ══════════════════════════════════════════════════════════════════════════════

let sigMissionId = null;
let sigDrawing = false;
let sigCanvas = null;
let sigCtx = null;
let sigHasContent = false;
let sigTerminerMode = false; // true = signature obligatoire pour terminer

function openSignatureModal(missionId, terminerMode){
  if(currentUser.isAdmin || currentUser.role === 'client'){
    showToast('⚠️ La signature est réservée aux monteurs sur le terrain');
    return;
  }
  const m = missions.find(m=>m.id===missionId);
  if(!m){ showToast('Mission introuvable'); return; }
  if(m.signature && !currentUser.isAdmin && !terminerMode){
    showToast('⚠️ Cette mission a déjà été signée');
    return;
  }
  sigMissionId = missionId;
  sigTerminerMode = !!terminerMode;
  document.getElementById('sig-nom').value = m.client || '';
  document.getElementById('sig-conforme').checked = m.conforme || false;

  // ★ Réinitialiser le champ photos
  const photosInput = document.getElementById('sig-photos');
  const photosPreview = document.getElementById('sig-photos-preview');
  if(photosInput){ photosInput.value = ''; }
  if(photosPreview){ photosPreview.innerHTML = ''; }
  // Listener prévisualisation photos
  if(photosInput){
    photosInput.onchange = function(){
      if(!photosPreview) return;
      photosPreview.innerHTML = '';
      Array.from(photosInput.files).forEach(file => {
        const reader = new FileReader();
        reader.onload = e => {
          const img = document.createElement('img');
          img.src = e.target.result;
          img.style.cssText = 'width:60px;height:60px;object-fit:cover;border-radius:6px;border:1.5px solid var(--border)';
          photosPreview.appendChild(img);
        };
        reader.readAsDataURL(file);
      });
    };
  }

  // ★ Adapter le titre et le bouton selon le mode
  const modal = document.getElementById('signature-modal');
  const titleEl = modal.querySelector('.modal-title span') || modal.querySelector('span');
  if(sigTerminerMode){
    // Mettre à jour le titre de la modale
    const headerSpan = modal.querySelector('div > span');
    if(headerSpan) headerSpan.textContent = '✍️ Signature requise pour terminer';
    // Mettre à jour le bouton valider
    const validateBtn = document.getElementById('sig-validate-btn');
    if(validateBtn) validateBtn.textContent = '✅ Valider et terminer l\'intervention';
  } else {
    const headerSpan = modal.querySelector('div > span');
    if(headerSpan) headerSpan.textContent = '✍️ Signature client';
    const validateBtn = document.getElementById('sig-validate-btn');
    if(validateBtn) validateBtn.textContent = '✅ Valider la signature';
  }

  document.getElementById('signature-modal').style.display = 'flex';
  setTimeout(initSignatureCanvas, 50);
}

function closeSignatureModal(){
  document.getElementById('signature-modal').style.display = 'none';
  sigMissionId = null;
  sigHasContent = false;
  sigTerminerMode = false;
  var banner = document.getElementById('duplicate-banner');
  if(banner) banner.remove();
}

function initSignatureCanvas(){
  sigCanvas = document.getElementById('sig-canvas');
  if(!sigCanvas){ console.error('[Sig] Canvas sig-canvas introuvable'); return; }
  const container = sigCanvas.parentElement;
  const w = container.offsetWidth - 4;
  const h = Math.max(160, Math.round(w * 0.4));
  sigCanvas.width = w;
  sigCanvas.height = h;
  sigCanvas.style.height = h + 'px';
  sigCtx = sigCanvas.getContext('2d');
  sigCtx.fillStyle = '#fff';
  sigCtx.fillRect(0, 0, w, h);
  sigCtx.strokeStyle = '#1a1a1a';
  sigCtx.lineWidth = 2.5;
  sigCtx.lineCap = 'round';
  sigCtx.lineJoin = 'round';
  sigHasContent = false;
  const ph = document.getElementById('sig-placeholder');
  if(ph) ph.style.display = 'block';

  // Supprimer anciens listeners en remplaçant le canvas
  const newCanvas = sigCanvas.cloneNode(true);
  sigCanvas.parentNode.replaceChild(newCanvas, sigCanvas);
  sigCanvas = newCanvas;
  sigCtx = sigCanvas.getContext('2d');
  sigCtx.fillStyle = '#fff';
  sigCtx.fillRect(0, 0, w, h);
  sigCtx.strokeStyle = '#1a1a1a';
  sigCtx.lineWidth = 2.5;
  sigCtx.lineCap = 'round';
  sigCtx.lineJoin = 'round';

  // Mouse events
  sigCanvas.addEventListener('mousedown', function(e){
    sigDrawing = true;
    sigCtx.beginPath();
    sigCtx.moveTo(...sigPos(e));
  });
  sigCanvas.addEventListener('mousemove', function(e){
    if(!sigDrawing) return;
    sigCtx.lineTo(...sigPos(e));
    sigCtx.stroke();
    sigHasContent = true;
    const p = document.getElementById('sig-placeholder');
    if(p) p.style.display = 'none';
  });
  sigCanvas.addEventListener('mouseup', function(){ sigDrawing = false; });
  sigCanvas.addEventListener('mouseleave', function(){ sigDrawing = false; });

  // Touch events (smartphone/tablette)
  sigCanvas.addEventListener('touchstart', function(e){
    e.preventDefault();
    sigDrawing = true;
    sigCtx.beginPath();
    sigCtx.moveTo(...sigPos(e.touches[0]));
  }, {passive: false});
  sigCanvas.addEventListener('touchmove', function(e){
    e.preventDefault();
    if(!sigDrawing) return;
    sigCtx.lineTo(...sigPos(e.touches[0]));
    sigCtx.stroke();
    sigHasContent = true;
    const p = document.getElementById('sig-placeholder');
    if(p) p.style.display = 'none';
  }, {passive: false});
  sigCanvas.addEventListener('touchend', function(){ sigDrawing = false; }, {passive: false});
  console.log('[Sig] Canvas initialisé:', w+'x'+h);
}

function sigPos(e){
  const rect = sigCanvas.getBoundingClientRect();
  const scaleX = sigCanvas.width / rect.width;
  const scaleY = sigCanvas.height / rect.height;
  return [(e.clientX - rect.left) * scaleX, (e.clientY - rect.top) * scaleY];
}

function clearSignature(){
  if(!sigCtx || !sigCanvas) return;
  sigCtx.fillStyle = '#fff';
  sigCtx.fillRect(0, 0, sigCanvas.width, sigCanvas.height);
  sigHasContent = false;
  const p = document.getElementById('sig-placeholder');
  if(p) p.style.display = 'block';
}

async function saveSignature(){
  if(!sigHasContent){ showToast('⚠️ Veuillez signer avant de valider'); return; }
  const m = missions.find(m=>m.id===sigMissionId);
  if(!m){ showToast('Mission introuvable'); return; }

  const nom = document.getElementById('sig-nom').value.trim() || 'Signataire';
  const conforme = document.getElementById('sig-conforme').checked;
  const now = new Date();
  const dateStr = now.toLocaleDateString('fr-FR');
  const heureStr = now.toLocaleTimeString('fr-FR',{hour:'2-digit',minute:'2-digit'});
  const sigDataUrl = sigCanvas.toDataURL('image/png');

  m.signature = {
    nom, date: dateStr, heure: heureStr,
    dataUrl: sigDataUrl,
    signedBy: currentUser.nom,
    missionId: sigMissionId,
    conforme
  };
  m.conforme = conforme;

  // ★ Si mode terminer : marquer la mission comme terminée
  if(sigTerminerMode){
    m.statut = 'termine';
    m.completedBy = currentUser.nom;
    m.completedAt = dateStr;
    m.completedTime = heureStr;
  }

  // ★ Upload des photos de fin de mission intégrées dans la validation
  const photosInput = document.getElementById('sig-photos');
  if(photosInput && photosInput.files && photosInput.files.length > 0){
    const progress = document.getElementById('sig-photos-progress');
    if(progress) progress.style.display = 'block';
    if(!m.attachments) m.attachments = [];
    const totalPhotos = photosInput.files.length;
    for(let i = 0; i < totalPhotos; i++){
      const file = photosInput.files[i];
      if(progress) progress.textContent = '⏳ Envoi photo ' + (i+1) + '/' + totalPhotos + '...';
      try {
        const base64 = await fileToBase64(file);
        const formData = new FormData();
        formData.append('key', IMGBB_KEY);
        formData.append('image', base64);
        formData.append('name', file.name);
        const res = await fetch('https://api.imgbb.com/1/upload', {method:'POST', body:formData});
        const data = await res.json();
        if(data.success && data.data && data.data.url){
          m.attachments.push({
            name: data.data.title || file.name,
            url: data.data.display_url || data.data.url,
            by: currentUser.nom,
            date: dateStr,
            time: heureStr,
            type: file.type,
            finDeMission: true
          });
        } else {
          console.log('[Signature] Erreur ImgBB photo:', data);
        }
      } catch(e){
        console.log('[Signature] Erreur upload photo:', e.message);
      }
    }
    if(progress) progress.style.display = 'none';
  }

  await saveMissionsToSheets();
  lastDataHash = '';
  closeSignatureModal();
  renderAll();

  if(sigTerminerMode){
    showToast('✅ Intervention terminée et signée !');
  } else {
    showToast('✅ Signature enregistrée !');
  }
}

