function renderClients(){
  const el = document.getElementById('clients-list');
  if(!el) return;
  if(!clients.length){
    el.innerHTML = '<div class="empty"><p>Aucun client. Cliquez sur "+ Nouveau client".</p></div>';
    return;
  }
  el.innerHTML = clients.map(c=>{
    // ★ Protection contre les champs undefined — normalisation des données
    const nom = c.nom || c.name || c.société || '(sans nom)';
    const login = c.login || c.username || c.identifiant || '(sans login)';
    const email = c.email || c.mail || '—';
    const actif = c.actif !== false;
    const cMissions = missions.filter(m=>m.clientId===c.id);
    const docsCount = cMissions.reduce((n,m)=>(m.attachments||[]).length+n, 0);
    return ` <div class="client-item" style="${!actif?'opacity:.55':''}"> <div class="client-avatar" style="background:var(--info)">${nom.charAt(0).toUpperCase()}</div> <div class="client-info"> <div class="client-name">${nom} ${!actif?'<span class="badge badge-grey" style="font-size:.7rem">Désactivé</span>':''}</div> <div class="client-meta">@${login} · ${email} · ${cMissions.length} mission(s) · ${docsCount} doc(s)${c.lastLogin?' · Connecté le '+c.lastLogin:''}</div> </div> <div class="emp-actions" style="flex-wrap:wrap;gap:.3rem"> <button class="btn btn-ghost btn-sm" onclick="openClientModal(${c.id})" title="Modifier">✏️</button> <button class="btn btn-ghost btn-sm" onclick="toggleClientActive(${c.id})" title="${!actif?'Réactiver':'Désactiver'}">${!actif?'✅':'⏸️'}</button> <button class="btn btn-ghost btn-sm" onclick="sendClientCredentials(${c.id})" title="Renvoyer identifiants">📧</button> <button class="btn btn-danger btn-sm" onclick="deleteClient(${c.id})" title="Supprimer">🗑️</button> </div> </div>`;
  }).join('');
}

async function sendClientCredentials(id){
  const c = clients.find(c=>c.id===id);
  if(!c || !c.email){ showToast('❌ Pas d\'email renseigné pour ce client'); return; }
  try {
    await fetch(SHEETS_URL, {
      method:'POST',
      headers:{'Content-Type':'text/plain'},
      body: JSON.stringify({
        action: 'send_client_credentials',
        clientId: c.id, nom: c.nom, email: c.email,
        login: c.login, pass: c.pass, appUrl: window.location.href
      })
    });
    showToast('📧 Identifiants envoyés à ' + c.email);
  } catch(e){
    showToast('❌ Erreur envoi email : ' + e.message);
  }
}

