  if(!el) return;
  const clientRecord = clients.find(c=>c.id===currentUser.id) || {nom: currentUser.nom};
  if(clientRecord.id){ clientRecord.lastLogin = new Date().toLocaleDateString('fr-FR'); saveClientsToSheets(); }

